INSERT INTO vocab_examples (id, vocabulary_id, word, sentence_en, sentence_zh) VALUES
  ('f49396df-535a-4baf-9c19-bf1375d1b8e7-ex1', 'f49396df-535a-4baf-9c19-bf1375d1b8e7', 'keyboard', 'The keyboard needs new batteries.', '键盘需要换电池了。'),
  ('f49396df-535a-4baf-9c19-bf1375d1b8e7-ex2', 'f49396df-535a-4baf-9c19-bf1375d1b8e7', 'keyboard', 'Keystroke logging without consent violates the surveillance statute.', '未经同意记录键盘输入违反监控法规。'),
  ('426f088d-569b-4f5c-bdbe-36134d4538f6-ex1', '426f088d-569b-4f5c-bdbe-36134d4538f6', 'kidnap', 'The movie is about a kidnapped scientist.', '这部电影讲述一位被绑架的科学家。'),
  ('426f088d-569b-4f5c-bdbe-36134d4538f6-ex2', '426f088d-569b-4f5c-bdbe-36134d4538f6', 'kidnap', 'The convention obliges states to criminalize kidnapping for ransom.', '该公约要求各国将勒索性绑架定为犯罪。'),
  ('3f761794-b67a-48b9-a9ff-7f3bdb1755a1-ex1', '3f761794-b67a-48b9-a9ff-7f3bdb1755a1', 'kidney', 'The kidneys filter your blood.', '肾脏过滤血液。'),
  ('3f761794-b67a-48b9-a9ff-7f3bdb1755a1-ex2', '3f761794-b67a-48b9-a9ff-7f3bdb1755a1', 'kidney', 'The registry tracks outcomes for every kidney transplant performed.', '登记系统追踪每例肾移植的结果。'),
  ('2712c571-12a8-4a08-9cb0-9dc730ddd2f7-ex1', '2712c571-12a8-4a08-9cb0-9dc730ddd2f7', 'kilometer', 'The school is two kilometers away.', '学校在两公里之外。'),
  ('2712c571-12a8-4a08-9cb0-9dc730ddd2f7-ex2', '2712c571-12a8-4a08-9cb0-9dc730ddd2f7', 'kilometer', 'The exclusion zone extends thirty kilometers from the facility.', '隔离区从该设施向外延伸三十公里。'),
  ('ba1ccef5-ee42-452b-b624-764fdd7dcb1f-ex1', 'ba1ccef5-ee42-452b-b624-764fdd7dcb1f', 'kindergarten', 'My daughter starts kindergarten this fall.', '我女儿今年秋天上幼儿园。'),
  ('ba1ccef5-ee42-452b-b624-764fdd7dcb1f-ex2', 'ba1ccef5-ee42-452b-b624-764fdd7dcb1f', 'kindergarten', 'Universal kindergarten access anchors the early education reform.', '幼儿园普及入学是早期教育改革的基石。'),
  ('fda0d74c-829b-42f3-8e7d-100485f5ab60-ex1', 'fda0d74c-829b-42f3-8e7d-100485f5ab60', 'landlord', 'The landlord fixed the heating quickly.', '房东很快修好了暖气。'),
  ('fda0d74c-829b-42f3-8e7d-100485f5ab60-ex2', 'fda0d74c-829b-42f3-8e7d-100485f5ab60', 'landlord', 'The landlord may not terminate absent the statutorily prescribed notice.', '未经法定通知程序，房东不得终止租约。'),
  ('d380fca5-3be5-49a9-b790-809925c9c819-ex1', 'd380fca5-3be5-49a9-b790-809925c9c819', 'laptop', 'She bought a new laptop for school.', '她为上学买了一台新笔记本电脑。'),
  ('d380fca5-3be5-49a9-b790-809925c9c819-ex2', 'd380fca5-3be5-49a9-b790-809925c9c819', 'laptop', 'The seized laptop yielded records central to the conspiracy count.', '查获的笔记本电脑提供了共谋罪名的核心记录。'),
  ('06a0e502-0ca8-4f8d-8a3f-781426160cb0-ex1', '06a0e502-0ca8-4f8d-8a3f-781426160cb0', 'large-scale', 'The factory began large-scale production.', '工厂开始了大规模生产。'),
  ('06a0e502-0ca8-4f8d-8a3f-781426160cb0-ex2', '06a0e502-0ca8-4f8d-8a3f-781426160cb0', 'large-scale', 'Large-scale surveillance requires individualized judicial authorization.', '大规模监控需要个案化的司法授权。'),
  ('acdd644f-ff20-4d84-83aa-340a6fec19c8-ex1', 'acdd644f-ff20-4d84-83aa-340a6fec19c8', 'latest', 'Have you seen the latest movie?', '你看过最新的电影吗？'),
  ('acdd644f-ff20-4d84-83aa-340a6fec19c8-ex2', 'acdd644f-ff20-4d84-83aa-340a6fec19c8', 'latest', 'The latest figures compelled a downward revision of the forecasts.', '最新数据迫使预测被向下修正。'),
  ('47282f28-37c6-48aa-9d58-5ac02cfc83ea-ex1', '47282f28-37c6-48aa-9d58-5ac02cfc83ea', 'layout', 'I like the layout of this apartment.', '我喜欢这套公寓的格局。'),
  ('47282f28-37c6-48aa-9d58-5ac02cfc83ea-ex2', '47282f28-37c6-48aa-9d58-5ac02cfc83ea', 'layout', 'The disclosure''s layout buried material risks in illegible footnotes.', '披露文件的版式把重大风险埋在难以辨读的脚注里。'),
  ('414a6f66-98eb-4dd4-b7b6-42fd3442ea25-ex1', '414a6f66-98eb-4dd4-b7b6-42fd3442ea25', 'lazy', 'The cat is too lazy to chase mice.', '这只猫懒得抓老鼠。'),
  ('414a6f66-98eb-4dd4-b7b6-42fd3442ea25-ex2', '414a6f66-98eb-4dd4-b7b6-42fd3442ea25', 'lazy', 'The dissent condemned the majority''s reasoning as analytically lazy.', '异议意见批评多数意见的推理在分析上流于敷衍。'),
  ('393f76ec-fa88-492d-8df3-6f251225abe0-ex1', '393f76ec-fa88-492d-8df3-6f251225abe0', 'leak', 'The roof has a small leak.', '屋顶有点漏水。'),
  ('393f76ec-fa88-492d-8df3-6f251225abe0-ex2', '393f76ec-fa88-492d-8df3-6f251225abe0', 'leak', 'The leak of the draft ruling triggered an unprecedented investigation.', '裁决草案的泄露引发了一场前所未有的调查。'),
  ('a3834d5a-9edc-4f82-99e5-28bac05be50e-ex1', 'a3834d5a-9edc-4f82-99e5-28bac05be50e', 'legendary', 'The coach is legendary at this school.', '这位教练在学校是传奇人物。'),
  ('a3834d5a-9edc-4f82-99e5-28bac05be50e-ex2', 'a3834d5a-9edc-4f82-99e5-28bac05be50e', 'legendary', 'The legendary deal-maker''s empire collapsed under forensic audit.', '这位传奇交易撮合者的商业帝国在法证审计下轰然倒塌。'),
  ('6840df61-27a7-41f6-b878-712bdecf690a-ex1', '6840df61-27a7-41f6-b878-712bdecf690a', 'leisure', 'She paints in her leisure time.', '她在闲暇时画画。'),
  ('6840df61-27a7-41f6-b878-712bdecf690a-ex2', '6840df61-27a7-41f6-b878-712bdecf690a', 'leisure', 'The directive guarantees minimum leisure entitlements for all workers.', '该指令保障所有劳动者的最低休息权利。'),
  ('0c6694a6-a9a8-4368-ac77-5fe8d1b60159-ex1', '0c6694a6-a9a8-4368-ac77-5fe8d1b60159', 'lengthy', 'The meeting was long and lengthy.', '会议冗长拖沓。'),
  ('0c6694a6-a9a8-4368-ac77-5fe8d1b60159-ex2', '0c6694a6-a9a8-4368-ac77-5fe8d1b60159', 'lengthy', 'After lengthy negotiation, the parties settled on confidential terms.', '经过漫长谈判，双方以保密条款达成和解。'),
  ('886b720d-4504-4e2a-a651-897d350302d8-ex1', '886b720d-4504-4e2a-a651-897d350302d8', 'lesbian', 'The film tells a lesbian love story.', '这部电影讲述了一段女同性恋爱情故事。'),
  ('886b720d-4504-4e2a-a651-897d350302d8-ex2', '886b720d-4504-4e2a-a651-897d350302d8', 'lesbian', 'The ruling extends employment protections to lesbian workers nationwide.', '该裁决将就业保护扩展至全国的女同性恋劳动者。'),
  ('6649d3ef-a8bc-4f7a-8af9-9cdd5ccabb8e-ex1', '6649d3ef-a8bc-4f7a-8af9-9cdd5ccabb8e', 'lesser', 'Choose the lesser of two evils.', '两害相权取其轻。'),
  ('6649d3ef-a8bc-4f7a-8af9-9cdd5ccabb8e-ex2', '6649d3ef-a8bc-4f7a-8af9-9cdd5ccabb8e', 'lesser', 'The defendant pleaded to a lesser offense in exchange for cooperation.', '被告以认可较轻罪名换取合作。'),
  ('ae8711e0-4a24-4a0c-95a9-c630cffbc1d7-ex1', 'ae8711e0-4a24-4a0c-95a9-c630cffbc1d7', 'lethal', 'Some mushrooms are lethal.', '有些蘑菇是致命的。'),
