  ('c6a63bb6-5c78-41da-ae8e-d3ec06a7f3a8-ex2', 'c6a63bb6-5c78-41da-ae8e-d3ec06a7f3a8', 'listing', 'The listing rules mandate disclosure of related-party transactions.', '上市规则强制要求披露关联交易。'),
