  ('57bddb04-ba90-4860-940c-cfce9a763dc2-ex1', '57bddb04-ba90-4860-940c-cfce9a763dc2', 'premier', 'The premier visited the flood zone.', '总理视察了洪灾区。'),
  ('57bddb04-ba90-4860-940c-cfce9a763dc2-ex2', '57bddb04-ba90-4860-940c-cfce9a763dc2', 'premier', 'The premier''s resignation triggered the coalition''s collapse.', '总理辞职引发了联合政府的垮台。'),
  ('0adc8848-aeab-4262-8a0e-07e6cd37e53a-ex1', '0adc8848-aeab-4262-8a0e-07e6cd37e53a', 'prepared', 'Be prepared for cold weather.', '为寒冷天气做好准备。'),
  ('0adc8848-aeab-4262-8a0e-07e6cd37e53a-ex2', '0adc8848-aeab-4262-8a0e-07e6cd37e53a', 'prepared', 'The tribunal was prepared to draw adverse inferences from the destruction.', '法庭准备就证据销毁作出不利推定。'),
  ('9536e0e8-8165-4c4a-bb2b-a18530ecc2dc-ex1', '9536e0e8-8165-4c4a-bb2b-a18530ecc2dc', 'prescribe', 'The doctor prescribed some medicine.', '医生开了一些药。'),
  ('9536e0e8-8165-4c4a-bb2b-a18530ecc2dc-ex2', '9536e0e8-8165-4c4a-bb2b-a18530ecc2dc', 'prescribe', 'The statute prescribes the procedure governing compulsory acquisition.', '该法规规定了强制征收所适用的程序。'),
  ('2283b42a-dd7c-4758-b20e-84d012a21caf-ex1', '2283b42a-dd7c-4758-b20e-84d012a21caf', 'presently', 'She is presently working abroad.', '她目前在国外工作。'),
  ('2283b42a-dd7c-4758-b20e-84d012a21caf-ex2', '2283b42a-dd7c-4758-b20e-84d012a21caf', 'presently', 'The framework presently in force predates the technologies it governs.', '现行框架的制定时间早于其所规范的技术。'),
  ('025d1b94-ec04-40f1-a509-06d70bbf4397-ex1', '025d1b94-ec04-40f1-a509-06d70bbf4397', 'preservation', 'The society works for forest preservation.', '该协会致力于森林保护。'),
  ('025d1b94-ec04-40f1-a509-06d70bbf4397-ex2', '025d1b94-ec04-40f1-a509-06d70bbf4397', 'preservation', 'Document preservation duties attach upon anticipation of litigation.', '一旦预见到诉讼，文件保存义务即告产生。'),
  ('7b0a7461-cf48-45f3-9f07-84014044dc85-ex1', '7b0a7461-cf48-45f3-9f07-84014044dc85', 'preside', 'The principal presided over the ceremony.', '校长主持了典礼。'),
  ('7b0a7461-cf48-45f3-9f07-84014044dc85-ex2', '7b0a7461-cf48-45f3-9f07-84014044dc85', 'preside', 'A senior judge will preside over the consolidated proceedings.', '一位资深法官将主持合并后的诉讼程序。'),
  ('a0f3b92f-c40d-48ca-b6b4-bc5e35d50fd0-ex1', 'a0f3b92f-c40d-48ca-b6b4-bc5e35d50fd0', 'prestigious', 'She attends a prestigious university.', '她就读于一所名牌大学。'),
  ('a0f3b92f-c40d-48ca-b6b4-bc5e35d50fd0-ex2', 'a0f3b92f-c40d-48ca-b6b4-bc5e35d50fd0', 'prestigious', 'The prestigious firm''s certification lent the scheme undeserved credibility.', '这家声誉卓著的事务所的认证给该方案带来了名不副实的可信度。'),
  ('34c74815-b002-4adc-9ce1-ba13a49fbdc5-ex1', '34c74815-b002-4adc-9ce1-ba13a49fbdc5', 'presume', 'I presume you have met before.', '我想你们以前见过。'),
  ('34c74815-b002-4adc-9ce1-ba13a49fbdc5-ex2', '34c74815-b002-4adc-9ce1-ba13a49fbdc5', 'presume', 'The law presumes innocence until guilt is established beyond doubt.', '法律推定无罪，直至排除合理怀疑地证明有罪。'),
  ('48366173-4393-4e90-8dad-69dfac292f91-ex1', '48366173-4393-4e90-8dad-69dfac292f91', 'prevalence', 'The survey measured the prevalence of smoking.', '调查统计了吸烟的普遍程度。'),
  ('48366173-4393-4e90-8dad-69dfac292f91-ex2', '48366173-4393-4e90-8dad-69dfac292f91', 'prevalence', 'The prevalence of evasion correlates with supervisory underfunding.', '规避行为的普遍程度与监管经费不足相关。'),
  ('a25fdb08-dc12-47dd-97d9-95f94c19ffd3-ex1', 'a25fdb08-dc12-47dd-97d9-95f94c19ffd3', 'prey', 'The owl hunts its prey at night.', '猫头鹰夜间捕猎。'),
  ('a25fdb08-dc12-47dd-97d9-95f94c19ffd3-ex2', 'a25fdb08-dc12-47dd-97d9-95f94c19ffd3', 'prey', 'The schemes prey on investors least equipped to assess the risk.', '这些骗局专门坑害最缺乏风险评估能力的投资者。'),
  ('2358f330-2739-484a-9129-a126e9d3ea64-ex1', '2358f330-2739-484a-9129-a126e9d3ea64', 'prince', 'The prince visited the children''s hospital.', '王子探访了儿童医院。'),
  ('2358f330-2739-484a-9129-a126e9d3ea64-ex2', '2358f330-2739-484a-9129-a126e9d3ea64', 'prince', 'The prince''s commercial dealings tested the boundaries of royal immunity.', '这位王子的商业往来考验着王室豁免的边界。'),
  ('e764c192-249d-422f-9148-378f77fb709c-ex1', 'e764c192-249d-422f-9148-378f77fb709c', 'princess', 'The princess opened the new library.', '公主为新图书馆揭幕。'),
  ('e764c192-249d-422f-9148-378f77fb709c-ex2', 'e764c192-249d-422f-9148-378f77fb709c', 'princess', 'The princess''s estate was administered under the dynastic trust.', '公主的遗产依据王室信托进行管理。'),
  ('5c307e84-c1e7-4d83-a675-27f37daee613-ex1', '5c307e84-c1e7-4d83-a675-27f37daee613', 'printer', 'The printer is out of paper.', '打印机没纸了。'),
  ('5c307e84-c1e7-4d83-a675-27f37daee613-ex2', '5c307e84-c1e7-4d83-a675-27f37daee613', 'printer', 'The printer bore joint liability for the defamatory publication.', '印刷商对诽谤性出版物承担连带责任。'),
  ('dc8fe95d-a121-4ae3-9e67-7c05285d414c-ex1', 'dc8fe95d-a121-4ae3-9e67-7c05285d414c', 'printing', 'The printing is clear and sharp.', '印刷清晰锐利。'),
  ('dc8fe95d-a121-4ae3-9e67-7c05285d414c-ex2', 'dc8fe95d-a121-4ae3-9e67-7c05285d414c', 'printing', 'The second printing corrected errors that had escaped the first.', '第二次印刷纠正了第一次印刷中漏掉的错误。'),
  ('a1fa11e3-26eb-4c40-ac7e-5d621caa7b7f-ex1', 'a1fa11e3-26eb-4c40-ac7e-5d621caa7b7f', 'privatization', 'The privatization of the railway was controversial.', '铁路私有化备受争议。'),
  ('a1fa11e3-26eb-4c40-ac7e-5d621caa7b7f-ex2', 'a1fa11e3-26eb-4c40-ac7e-5d621caa7b7f', 'privatization', 'The privatization proceeded without the safeguards the auditors urged.', '私有化在缺乏审计师所敦促的保障措施下推进。'),
  ('06a5be28-015e-4e7b-a1df-e9162cabad47-ex1', '06a5be28-015e-4e7b-a1df-e9162cabad47', 'probability', 'There is a high probability of rain.', '下雨的可能性很大。'),
  ('06a5be28-015e-4e7b-a1df-e9162cabad47-ex2', '06a5be28-015e-4e7b-a1df-e9162cabad47', 'probability', 'The standard requires proof on the balance of probabilities.', '该标准要求按盖然性占优的程度加以证明。'),
  ('f2e4fdd5-5eb7-4871-ad07-a3a9dcd994d1-ex1', 'f2e4fdd5-5eb7-4871-ad07-a3a9dcd994d1', 'probable', 'Rain is probable this afternoon.', '今天下午可能下雨。'),
  ('f2e4fdd5-5eb7-4871-ad07-a3a9dcd994d1-ex2', 'f2e4fdd5-5eb7-4871-ad07-a3a9dcd994d1', 'probable', 'Arrest requires probable cause judicially determined.', '逮捕需要经法院认定的合理根据。'),
  ('5137af00-488f-42e0-b23b-a9bdbf43606b-ex1', '5137af00-488f-42e0-b23b-a9bdbf43606b', 'probe', 'The doctor probed the wound gently.', '医生轻轻探查伤口。'),
  ('5137af00-488f-42e0-b23b-a9bdbf43606b-ex2', '5137af00-488f-42e0-b23b-a9bdbf43606b', 'probe', 'The probe uncovered transactions spanning a dozen jurisdictions.', '这次调查揭露了横跨十几个司法管辖区的交易。'),
  ('3734d21e-23c0-4aa5-a9a6-df63c8cbf035-ex1', '3734d21e-23c0-4aa5-a9a6-df63c8cbf035', 'problematic', 'The old wiring is problematic.', '老旧的线路存在隐患。'),
  ('3734d21e-23c0-4aa5-a9a6-df63c8cbf035-ex2', '3734d21e-23c0-4aa5-a9a6-df63c8cbf035', 'problematic', 'The delegation of enforcement to private auditors proved problematic.', '将执法委托给私营审计机构的做法被证明问题重重。'),
  ('1e1bf8ae-ba42-4573-9a33-ba12b0045d8a-ex1', '1e1bf8ae-ba42-4573-9a33-ba12b0045d8a', 'proceeding', 'The meeting''s proceedings were recorded.', '会议过程做了记录。'),
  ('1e1bf8ae-ba42-4573-9a33-ba12b0045d8a-ex2', '1e1bf8ae-ba42-4573-9a33-ba12b0045d8a', 'proceeding', 'The proceeding was stayed pending the constitutional reference.', '在宪法问题提请裁决期间，该诉讼程序被中止。'),
  ('ace0c310-b50b-4969-9811-bd716d6394ce-ex1', 'ace0c310-b50b-4969-9811-bd716d6394ce', 'proceeds', 'The proceeds of the sale go to charity.', '义卖所得捐给慈善机构。'),
  ('ace0c310-b50b-4969-9811-bd716d6394ce-ex2', 'ace0c310-b50b-4969-9811-bd716d6394ce', 'proceeds', 'The proceeds of crime remain forfeitable wherever transferred.', '犯罪所得无论转移到哪里都可予以没收。'),
  ('03cedb25-a4c5-431f-a0ce-49b4bbc51631-ex1', '03cedb25-a4c5-431f-a0ce-49b4bbc51631', 'profitable', 'The bakery became profitable last year.', '这家面包店去年开始盈利。'),
  ('03cedb25-a4c5-431f-a0ce-49b4bbc51631-ex2', '03cedb25-a4c5-431f-a0ce-49b4bbc51631', 'profitable', 'The division, though profitable, was divested to satisfy the remedy.', '该部门虽然盈利，仍为履行救济措施而被剥离。'),
  ('66f806d9-f02d-40ef-8180-fc2b6b1bcf85-ex1', '66f806d9-f02d-40ef-8180-fc2b6b1bcf85', 'pronounce', 'How do you pronounce this word?', '这个词怎么发音？'),
  ('66f806d9-f02d-40ef-8180-fc2b6b1bcf85-ex2', '66f806d9-f02d-40ef-8180-fc2b6b1bcf85', 'pronounce', 'The court will pronounce judgment at a date to be notified.', '法院将在另行通知的日期宣判。'),
  ('ade7d049-c98e-42a2-a360-82f521ebf4c0-ex1', 'ade7d049-c98e-42a2-a360-82f521ebf4c0', 'pronounced', 'She speaks with a pronounced accent.', '她说话带着明显的口音。'),
  ('ade7d049-c98e-42a2-a360-82f521ebf4c0-ex2', 'ade7d049-c98e-42a2-a360-82f521ebf4c0', 'pronounced', 'The divergence between regions grew more pronounced each year.', '地区之间的差异逐年愈发明显。'),
  ('d022ee5b-e37c-4e8f-8082-6634146e9ca6-ex1', 'd022ee5b-e37c-4e8f-8082-6634146e9ca6', 'propaganda', 'The poster was pure propaganda.', '这张海报纯属宣传。'),
  ('d022ee5b-e37c-4e8f-8082-6634146e9ca6-ex2', 'd022ee5b-e37c-4e8f-8082-6634146e9ca6', 'propaganda', 'The tribunal distinguished protected expression from incitement propaganda.', '法庭将受保护的言论与煽动性宣传区分开来。'),
  ('a93ae64b-b392-4c57-a337-b623290ddc8e-ex1', 'a93ae64b-b392-4c57-a337-b623290ddc8e', 'proposition', 'That sounds like a fair proposition.', '这听起来是个公平的提议。'),
  ('a93ae64b-b392-4c57-a337-b623290ddc8e-ex2', 'a93ae64b-b392-4c57-a337-b623290ddc8e', 'proposition', 'The dissent rejected the majority''s core proposition root and branch.', '异议意见彻底否定了多数意见的核心命题。'),
  ('d980d8e0-8c7a-4015-bde4-158827cab163-ex1', 'd980d8e0-8c7a-4015-bde4-158827cab163', 'prospective', 'They showed the house to prospective buyers.', '他们带潜在买家看了房子。'),
  ('d980d8e0-8c7a-4015-bde4-158827cab163-ex2', 'd980d8e0-8c7a-4015-bde4-158827cab163', 'prospective', 'The ruling applies prospectively, disturbing no settled transaction.', '该裁决仅向后适用，不影响任何已了结的交易。'),
  ('aa264b65-9950-4120-9efe-1e18ba85c883-ex1', 'aa264b65-9950-4120-9efe-1e18ba85c883', 'prosperity', 'The town enjoyed years of prosperity.', '这个镇享受了多年的繁荣。'),
  ('aa264b65-9950-4120-9efe-1e18ba85c883-ex2', 'aa264b65-9950-4120-9efe-1e18ba85c883', 'prosperity', 'Prosperity long masked the structural imbalances the crisis exposed.', '长期的繁荣掩盖了危机所暴露的结构性失衡。'),
  ('69645c1c-f4d4-4ca7-a141-c05dfe719264-ex1', '69645c1c-f4d4-4ca7-a141-c05dfe719264', 'protester', 'The protesters marched peacefully.', '抗议者和平游行。'),
  ('69645c1c-f4d4-4ca7-a141-c05dfe719264-ex2', '69645c1c-f4d4-4ca7-a141-c05dfe719264', 'protester', 'The inquiry examined whether force used against protesters was proportionate.', '调查审查了对抗议者使用武力是否相称。'),
  ('6dc7961e-e1a4-4120-b1b0-519d6a9f2f17-ex1', '6dc7961e-e1a4-4120-b1b0-519d6a9f2f17', 'provincial', 'She works for the provincial government.', '她在省政府工作。'),
  ('6dc7961e-e1a4-4120-b1b0-519d6a9f2f17-ex2', '6dc7961e-e1a4-4120-b1b0-519d6a9f2f17', 'provincial', 'Provincial authorities administer the program under uniform national oversight.', '省级当局在全国统一监督下实施该项目。'),
  ('bb2d24af-85c3-41c4-81e8-445f9829bdd5-ex1', 'bb2d24af-85c3-41c4-81e8-445f9829bdd5', 'psychiatric', 'He sought psychiatric help.', '他寻求了精神科帮助。'),
  ('bb2d24af-85c3-41c4-81e8-445f9829bdd5-ex2', 'bb2d24af-85c3-41c4-81e8-445f9829bdd5', 'psychiatric', 'The court ordered a psychiatric evaluation of the defendant''s fitness to stand trial.', '法院下令对被告的受审能力进行精神评估。'),
  ('6ea55505-627b-4238-a53e-5c7444905c1f-ex1', '6ea55505-627b-4238-a53e-5c7444905c1f', 'publishing', 'She works in book publishing.', '她从事图书出版工作。'),
  ('6ea55505-627b-4238-a53e-5c7444905c1f-ex2', '6ea55505-627b-4238-a53e-5c7444905c1f', 'publishing', 'The publishing house defended the report on grounds of public interest.', '出版社以公共利益为由为该报道辩护。'),
  ('1fccf22f-cb54-47d8-9c00-f996da26d7ad-ex1', '1fccf22f-cb54-47d8-9c00-f996da26d7ad', 'punk', 'He loves listening to punk music.', '他喜欢听朋克音乐。'),
  ('1fccf22f-cb54-47d8-9c00-f996da26d7ad-ex2', '1fccf22f-cb54-47d8-9c00-f996da26d7ad', 'punk', 'The punk movement reshaped the recording industry''s commercial assumptions.', '朋克运动重塑了唱片业的商业假设。'),
  ('c0809991-f207-4b5c-b7f9-828f1cd962eb-ex1', 'c0809991-f207-4b5c-b7f9-828f1cd962eb', 'purely', 'It happened purely by chance.', '这纯属偶然。'),
  ('c0809991-f207-4b5c-b7f9-828f1cd962eb-ex2', 'c0809991-f207-4b5c-b7f9-828f1cd962eb', 'purely', 'The arrangement is purely commercial and attracts no sovereign immunity.', '该安排纯属商业性质，不享有任何主权豁免。'),
  ('c4557eba-ff7e-49ec-a7cd-83a3423e1e0c-ex1', 'c4557eba-ff7e-49ec-a7cd-83a3423e1e0c', 'qualification', 'What qualifications do you need?', '你需要什么资格？'),
  ('c4557eba-ff7e-49ec-a7cd-83a3423e1e0c-ex2', 'c4557eba-ff7e-49ec-a7cd-83a3423e1e0c', 'qualification', 'The admission of liability was hedged with material qualifications.', '对责任的承认附加了重大的保留限定。')
INSERT INTO vocab_examples (id, vocabulary_id, word, sentence_en, sentence_zh) VALUES
  ('51051c32-6645-47fd-8542-e725ee5e28fd-ex1', '51051c32-6645-47fd-8542-e725ee5e28fd', 'qualified', 'She is qualified to teach math.', '她有资格教数学。'),
  ('51051c32-6645-47fd-8542-e725ee5e28fd-ex2', '51051c32-6645-47fd-8542-e725ee5e28fd', 'qualified', 'The auditor issued a qualified opinion on the consolidated statements.', '审计师对合并报表出具了保留意见。'),
  ('87a82048-532c-47fb-8e6e-4785a88ba21f-ex1', '87a82048-532c-47fb-8e6e-4785a88ba21f', 'quota', 'The team met its sales quota.', '团队完成了销售配额。'),
  ('87a82048-532c-47fb-8e6e-4785a88ba21f-ex2', '87a82048-532c-47fb-8e6e-4785a88ba21f', 'quota', 'Import quotas became the central flashpoint of the trade negotiation.', '进口配额成了贸易谈判的核心争点。'),
  ('ea3d5a76-ce87-4183-bf76-8ddd42ba1f27-ex1', 'ea3d5a76-ce87-4183-bf76-8ddd42ba1f27', 'quotation', 'The essay opens with a famous quotation.', '这篇文章以一句名言开头。'),
  ('ea3d5a76-ce87-4183-bf76-8ddd42ba1f27-ex2', 'ea3d5a76-ce87-4183-bf76-8ddd42ba1f27', 'quotation', 'The judgment buttresses each proposition with a precise quotation.', '判决书以精确引文支撑每一论点。'),
  ('c99d6dba-4757-420b-ac77-ae1556aab3a1-ex1', 'c99d6dba-4757-420b-ac77-ae1556aab3a1', 'racing', 'He enjoys watching horse racing.', '他喜欢看赛马。'),
  ('c99d6dba-4757-420b-ac77-ae1556aab3a1-ex2', 'c99d6dba-4757-420b-ac77-ae1556aab3a1', 'racing', 'Regulators are racing to keep pace with the evolving typology of fraud.', '监管者正争分夺秒地跟上欺诈手法的演变。'),
  ('fd27798b-e132-4463-9a82-aa923589fec9-ex1', 'fd27798b-e132-4463-9a82-aa923589fec9', 'racist', 'The comment was clearly racist.', '这番话明显带有种族主义色彩。'),
  ('fd27798b-e132-4463-9a82-aa923589fec9-ex2', 'fd27798b-e132-4463-9a82-aa923589fec9', 'racist', 'The statute criminalizes incitement grounded in racist hatred.', '该法规将基于种族仇恨的煽动定为犯罪。'),
  ('8380855c-0f89-4ad8-91f7-18c189742c34-ex1', '8380855c-0f89-4ad8-91f7-18c189742c34', 'raid', 'The police carried out a dawn raid.', '警方实施了一次黎明搜查。'),
  ('8380855c-0f89-4ad8-91f7-18c189742c34-ex2', '8380855c-0f89-4ad8-91f7-18c189742c34', 'raid', 'The raid yielded records central to the conspiracy prosecution.', '这次搜查获取了共谋起诉的核心记录。'),
  ('438efc08-b294-4c23-8ea9-86778f8f6dce-ex1', '438efc08-b294-4c23-8ea9-86778f8f6dce', 'ranking', 'The team rose in the league ranking.', '球队的联赛排名上升了。'),
  ('438efc08-b294-4c23-8ea9-86778f8f6dce-ex2', '438efc08-b294-4c23-8ea9-86778f8f6dce', 'ranking', 'The credit ranking was downgraded following the disclosed shortfall.', '缺口披露后，信用评级遭到下调。'),
  ('f3722df1-e69e-4c64-b656-da1ff76beeb9-ex1', 'f3722df1-e69e-4c64-b656-da1ff76beeb9', 'ray', 'A ray of sunlight came through the window.', '一缕阳光透过窗户照进来。'),
