  ('53d1a9cd-c365-4ad8-905e-f30a433c89bb-ex1', '53d1a9cd-c365-4ad8-905e-f30a433c89bb', 'subscription', 'I canceled my magazine subscription.', '我取消了杂志订阅。'),
