  ('f43beec9-06e4-48e1-9192-a6d4de031c9e-ex1', 'f43beec9-06e4-48e1-9192-a6d4de031c9e', 'thirsty', 'I am thirsty; may I have some water?', '我口渴了，能喝点水吗？'),
  ('f43beec9-06e4-48e1-9192-a6d4de031c9e-ex2', 'f43beec9-06e4-48e1-9192-a6d4de031c9e', 'thirsty', 'Capital thirsty for yield ignored the embedded credit risk.', '渴求收益的资本忽视了内嵌的信用风险。'),
