  ('ef2ee6c8-3a6e-425c-b0f6-f74e807a12ec-ex2', 'ef2ee6c8-3a6e-425c-b0f6-f74e807a12ec', 'thirteen', 'The protocol''s thirteen articles codify the verification regime.', '该议定书的十三条条文确立了核查制度。'),
  ('52ac0a2b-3308-4a6c-954f-8042a639dc57-ex1', '52ac0a2b-3308-4a6c-954f-8042a639dc57', 'thorough', 'She did a thorough job cleaning.', '她把清洁工作做得很彻底。'),
  ('52ac0a2b-3308-4a6c-954f-8042a639dc57-ex2', '52ac0a2b-3308-4a6c-954f-8042a639dc57', 'thorough', 'The court demanded a thorough accounting of the disputed transactions.', '法院要求对争议交易进行彻底的会计核算。'),
  ('771682e4-7c4c-4f5e-a256-c6ad164e4b57-ex1', '771682e4-7c4c-4f5e-a256-c6ad164e4b57', 'thought-provoking', 'The film was thought-provoking.', '这部电影发人深省。'),
  ('771682e4-7c4c-4f5e-a256-c6ad164e4b57-ex2', '771682e4-7c4c-4f5e-a256-c6ad164e4b57', 'thought-provoking', 'The dissent offers a thought-provoking critique of unchecked delegation.', '异议意见对不受约束的授权提出了发人深省的批评。'),
  ('2fadae99-2419-4830-a2b3-2e523fbfc865-ex1', '2fadae99-2419-4830-a2b3-2e523fbfc865', 'thoughtful', 'That was a thoughtful gift.', '那是一份贴心的礼物。'),
  ('2fadae99-2419-4830-a2b3-2e523fbfc865-ex2', '2fadae99-2419-4830-a2b3-2e523fbfc865', 'thoughtful', 'The opinion reflects a thoughtful balancing of competing constitutional values.', '该判决意见体现了对相互竞争的宪法价值的审慎权衡。'),
  ('253b6546-eb87-4f15-a8d6-163430abf5ce-ex1', '253b6546-eb87-4f15-a8d6-163430abf5ce', 'thrilled', 'She was thrilled to win the prize.', '获奖让她欣喜若狂。'),
  ('253b6546-eb87-4f15-a8d6-163430abf5ce-ex2', '253b6546-eb87-4f15-a8d6-163430abf5ce', 'thrilled', 'Investors were thrilled until the contingent liabilities surfaced.', '在或有负债浮出水面之前，投资者欣喜不已。'),
  ('98d97787-88e3-4a65-a065-5ac0e4f813b6-ex1', '98d97787-88e3-4a65-a065-5ac0e4f813b6', 'thursday', 'The meeting is on Thursday.', '会议在周四。'),
  ('98d97787-88e3-4a65-a065-5ac0e4f813b6-ex2', '98d97787-88e3-4a65-a065-5ac0e4f813b6', 'thursday', 'The committee reconvenes each Thursday during the legislative session.', '在立法会期内，委员会每周四复会。'),
  ('ae4fc3c1-573a-49cb-9e0e-982f36c33062-ex1', 'ae4fc3c1-573a-49cb-9e0e-982f36c33062', 'timely', 'Thank you for your timely help.', '谢谢你及时的帮助。'),
  ('ae4fc3c1-573a-49cb-9e0e-982f36c33062-ex2', 'ae4fc3c1-573a-49cb-9e0e-982f36c33062', 'timely', 'Timely disclosure would have averted much of the eventual harm.', '及时披露本可避免大部分最终损害。'),
  ('7f5ac0b9-7845-40cc-8d47-92120d8db4bf-ex1', '7f5ac0b9-7845-40cc-8d47-92120d8db4bf', 'ton', 'The truck carries ten tons of sand.', '这辆卡车装载十吨沙子。'),
  ('7f5ac0b9-7845-40cc-8d47-92120d8db4bf-ex2', '7f5ac0b9-7845-40cc-8d47-92120d8db4bf', 'ton', 'The levy is assessed per ton of verified carbon emissions.', '该税项按每吨经核证的碳排放量计征。'),
  ('c0651c19-c4e7-4592-bf6b-30f7eb0d30ee-ex1', 'c0651c19-c4e7-4592-bf6b-30f7eb0d30ee', 'torture', 'The waiting was pure torture.', '等待简直是煎熬。'),
  ('c0651c19-c4e7-4592-bf6b-30f7eb0d30ee-ex2', 'c0651c19-c4e7-4592-bf6b-30f7eb0d30ee', 'torture', 'The convention prohibits torture absolutely, admitting no exception.', '该公约绝对禁止酷刑，不容任何例外。'),
  ('a0ca1676-7081-4d79-b745-b1dbaabcfe9c-ex1', 'a0ca1676-7081-4d79-b745-b1dbaabcfe9c', 'trademark', 'The logo is a registered trademark.', '这个标志是注册商标。'),
  ('a0ca1676-7081-4d79-b745-b1dbaabcfe9c-ex2', 'a0ca1676-7081-4d79-b745-b1dbaabcfe9c', 'trademark', 'The counterfeit goods infringed a trademark registered in member states.', '这些假冒商品侵犯了在成员国注册的商标。'),
  ('afca0bcc-f05e-4451-8ca3-692cc7aea2d4-ex1', 'afca0bcc-f05e-4451-8ca3-692cc7aea2d4', 'transcript', 'She requested her academic transcript.', '她申请了成绩单。'),
  ('afca0bcc-f05e-4451-8ca3-692cc7aea2d4-ex2', 'afca0bcc-f05e-4451-8ca3-692cc7aea2d4', 'transcript', 'The hearing transcript preserved the objection for appellate review.', '庭审记录保留了该异议，以备上诉审查。'),
  ('7ed77f27-cc8b-47ce-a37c-78864bc5202b-ex1', '7ed77f27-cc8b-47ce-a37c-78864bc5202b', 'transparency', 'The company promised more transparency.', '公司承诺提高透明度。'),
  ('7ed77f27-cc8b-47ce-a37c-78864bc5202b-ex2', '7ed77f27-cc8b-47ce-a37c-78864bc5202b', 'transparency', 'Transparency is the indispensable precondition of credible oversight.', '透明度是可信监督不可或缺的前提。'),
  ('ad3e9c13-966c-4ec1-9590-1a3e55363b04-ex1', 'ad3e9c13-966c-4ec1-9590-1a3e55363b04', 'transparent', 'The water is clear and transparent.', '水清澈透明。'),
  ('ad3e9c13-966c-4ec1-9590-1a3e55363b04-ex2', 'ad3e9c13-966c-4ec1-9590-1a3e55363b04', 'transparent', 'The allocation process must be transparent and free of favoritism.', '分配过程必须透明且杜绝偏私。'),
  ('62dc2fe9-907e-4dea-aa01-7d2fcc698989-ex1', '62dc2fe9-907e-4dea-aa01-7d2fcc698989', 'tribute', 'They paid tribute to the late teacher.', '他们向已故的老师致敬。'),
  ('62dc2fe9-907e-4dea-aa01-7d2fcc698989-ex2', '62dc2fe9-907e-4dea-aa01-7d2fcc698989', 'tribute', 'The restored hall stands as a tribute to sustained private patronage.', '修复后的大厅是对持续私人资助的致敬。'),
  ('18a614f9-359a-4b41-b2d3-fdea5dc696bb-ex1', '18a614f9-359a-4b41-b2d3-fdea5dc696bb', 'trillion', 'The number is over a trillion.', '这个数字超过一万亿。'),
  ('18a614f9-359a-4b41-b2d3-fdea5dc696bb-ex2', '18a614f9-359a-4b41-b2d3-fdea5dc696bb', 'trillion', 'The aggregate exposure ran into the trillions across interconnected markets.', '在相互关联的市场中，总风险敞口高达数万亿。'),
  ('21e72a92-76f2-4822-a429-ea7830ffaeeb-ex1', '21e72a92-76f2-4822-a429-ea7830ffaeeb', 'trio', 'The jazz trio played all night.', '爵士三重奏演奏了一整夜。'),
  ('21e72a92-76f2-4822-a429-ea7830ffaeeb-ex2', '21e72a92-76f2-4822-a429-ea7830ffaeeb', 'trio', 'A trio of converging factors precipitated the institution''s collapse.', '三重因素的叠加促成了该机构的崩溃。'),
  ('1b5b19af-2b18-49c4-9109-0b0780357d7a-ex1', '1b5b19af-2b18-49c4-9109-0b0780357d7a', 'trophy', 'She lifted the trophy proudly.', '她自豪地举起奖杯。'),
  ('1b5b19af-2b18-49c4-9109-0b0780357d7a-ex2', '1b5b19af-2b18-49c4-9109-0b0780357d7a', 'trophy', 'The acquisition proved a trophy asset that drained, rather than added, value.', '这笔收购被证明是一项耗损而非增值的面子资产。'),
  ('549f38c0-c0da-48b2-b311-7ea1b6d8eaaa-ex1', '549f38c0-c0da-48b2-b311-7ea1b6d8eaaa', 'trustee', 'The trustee manages the charity''s funds.', '受托人管理慈善机构的资金。'),
  ('549f38c0-c0da-48b2-b311-7ea1b6d8eaaa-ex2', '549f38c0-c0da-48b2-b311-7ea1b6d8eaaa', 'trustee', 'The trustee owes undivided loyalty to every beneficiary of the trust.', '受托人对信托的每位受益人都负有完全的忠实义务。'),
  ('1f3c71d9-bbf5-4981-b66e-3d66a6fa8a40-ex1', '1f3c71d9-bbf5-4981-b66e-3d66a6fa8a40', 'tsunami', 'The tsunami warning cleared the beach.', '海啸预警使海滩上的人撤离。'),
  ('1f3c71d9-bbf5-4981-b66e-3d66a6fa8a40-ex2', '1f3c71d9-bbf5-4981-b66e-3d66a6fa8a40', 'tsunami', 'The disclosure unleashed a tsunami of redemption requests overnight.', '这次披露一夜之间引发了赎回申请的海啸。'),
  ('2953d7ce-91ab-4508-ba39-b49d65d25c87-ex1', '2953d7ce-91ab-4508-ba39-b49d65d25c87', 'tuesday', 'The class meets every Tuesday.', '这门课每周二上。'),
  ('2953d7ce-91ab-4508-ba39-b49d65d25c87-ex2', '2953d7ce-91ab-4508-ba39-b49d65d25c87', 'tuesday', 'The committee reconvenes each Tuesday during the session.', '在会期内，委员会每周二复会。'),
  ('02f00c5b-1b45-4af5-98bb-446c4b1e852c-ex1', '02f00c5b-1b45-4af5-98bb-446c4b1e852c', 'tuition', 'College tuition keeps rising.', '大学学费不断上涨。'),
  ('02f00c5b-1b45-4af5-98bb-446c4b1e852c-ex2', '02f00c5b-1b45-4af5-98bb-446c4b1e852c', 'tuition', 'Rising tuition renewed debate over public financing of higher education.', '学费上涨重新引发了关于高等教育公共资助的辩论。'),
  ('cc229df5-564c-48b2-8c79-ab3b2a7adeff-ex1', 'cc229df5-564c-48b2-8c79-ab3b2a7adeff', 'turnout', 'Voter turnout was high this year.', '今年投票率很高。'),
  ('cc229df5-564c-48b2-8c79-ab3b2a7adeff-ex2', 'cc229df5-564c-48b2-8c79-ab3b2a7adeff', 'turnout', 'A modest shift in turnout would have reversed the entire outcome.', '投票率的小幅变化就足以逆转整个结果。'),
  ('89bffe83-5e52-4d2d-87a5-f685d158aade-ex1', '89bffe83-5e52-4d2d-87a5-f685d158aade', 'turnover', 'The restaurant has high staff turnover.', '这家餐厅员工流动率高。'),
  ('89bffe83-5e52-4d2d-87a5-f685d158aade-ex2', '89bffe83-5e52-4d2d-87a5-f685d158aade', 'turnover', 'Penalties may reach ten percent of verified annual turnover.', '处罚可达经核实年营业额的百分之十。'),
  ('5ffe083f-531d-474c-ba20-819548633b90-ex1', '5ffe083f-531d-474c-ba20-819548633b90', 'umbrella', 'Take an umbrella; it might rain.', '带把伞，可能会下雨。'),
  ('5ffe083f-531d-474c-ba20-819548633b90-ex2', '5ffe083f-531d-474c-ba20-819548633b90', 'umbrella', 'The directive operates as an umbrella framework over divergent national rules.', '该指令作为一个总括性框架统领各不相同的国家规则。'),
  ('7b041008-9443-44fd-8f0f-0ab12f371db4-ex1', '7b041008-9443-44fd-8f0f-0ab12f371db4', 'unacceptable', 'That kind of behavior is unacceptable.', '那种行为是不可接受的。'),
  ('7b041008-9443-44fd-8f0f-0ab12f371db4-ex2', '7b041008-9443-44fd-8f0f-0ab12f371db4', 'unacceptable', 'The tribunal deemed the delay unacceptable and imposed sanctions.', '法庭认定这种拖延不可接受，并施加了处罚。'),
  ('ce580bd7-3344-43a3-9bcd-15bf41f594e7-ex1', 'ce580bd7-3344-43a3-9bcd-15bf41f594e7', 'unconscious', 'He was unconscious for a few minutes.', '他昏迷了几分钟。'),
  ('ce580bd7-3344-43a3-9bcd-15bf41f594e7-ex2', 'ce580bd7-3344-43a3-9bcd-15bf41f594e7', 'unconscious', 'Unconscious bias in selection perpetuated the disparities the directive prohibits.', '遴选中的无意识偏见固化了该指令所禁止的差异。'),
  ('551e682b-a393-44f2-85f7-1d71c899ad20-ex1', '551e682b-a393-44f2-85f7-1d71c899ad20', 'unconstitutional', 'The court ruled the law unconstitutional.', '法院裁定该法律违宪。'),
  ('551e682b-a393-44f2-85f7-1d71c899ad20-ex2', '551e682b-a393-44f2-85f7-1d71c899ad20', 'unconstitutional', 'The measure was struck down as unconstitutional for exceeding legislative authority.', '该措施因超出立法权限而被裁定违宪废止。'),
  ('e1396b8d-7936-4684-8ee5-cd45dd3ed781-ex1', 'e1396b8d-7936-4684-8ee5-cd45dd3ed781', 'underground', 'The parking is underground.', '停车场在地下。'),
  ('e1396b8d-7936-4684-8ee5-cd45dd3ed781-ex2', 'e1396b8d-7936-4684-8ee5-cd45dd3ed781', 'underground', 'An underground economy flourished beyond the reach of taxation.', '地下经济在税收触及不到的地方蓬勃滋长。')
INSERT INTO vocab_examples (id, vocabulary_id, word, sentence_en, sentence_zh) VALUES
  ('154ef373-6494-4c34-90c0-478c14c72e8f-ex1', '154ef373-6494-4c34-90c0-478c14c72e8f', 'underwear', 'Pack extra underwear for the trip.', '旅行多带几件内衣。'),
  ('154ef373-6494-4c34-90c0-478c14c72e8f-ex2', '154ef373-6494-4c34-90c0-478c14c72e8f', 'underwear', 'The seized underwear bore counterfeit marks of protected brands.', '查获的内衣带有受保护品牌的假冒标识。'),
  ('9fb7c7be-85d8-43ce-8687-6ffcef2904e5-ex1', '9fb7c7be-85d8-43ce-8687-6ffcef2904e5', 'undoubtedly', 'She is undoubtedly the best player.', '她无疑是最优秀的球员。'),
  ('9fb7c7be-85d8-43ce-8687-6ffcef2904e5-ex2', '9fb7c7be-85d8-43ce-8687-6ffcef2904e5', 'undoubtedly', 'The reforms undoubtedly helped, yet structural drivers remained untouched.', '这些改革无疑有所助益，但结构性根源仍未触及。'),
  ('fcd710d3-c6ef-4518-be23-5cf45a93c58b-ex1', 'fcd710d3-c6ef-4518-be23-5cf45a93c58b', 'unemployed', 'He has been unemployed for months.', '他失业好几个月了。'),
  ('fcd710d3-c6ef-4518-be23-5cf45a93c58b-ex2', 'fcd710d3-c6ef-4518-be23-5cf45a93c58b', 'unemployed', 'The reforms extend retraining entitlements to the long-term unemployed.', '这些改革将再培训权利扩展至长期失业者。'),
  ('b662bad8-9bd3-4f7e-a21a-12aeec5e0121-ex1', 'b662bad8-9bd3-4f7e-a21a-12aeec5e0121', 'unfortunate', 'It was an unfortunate accident.', '那是一起不幸的事故。'),
  ('b662bad8-9bd3-4f7e-a21a-12aeec5e0121-ex2', 'b662bad8-9bd3-4f7e-a21a-12aeec5e0121', 'unfortunate', 'The unfortunate drafting invited the very abuse the statute targeted.', '不当的起草招致了法规本欲打击的滥用。'),
  ('abfa3dc5-58ea-46da-9215-17e7072ff5fc-ex1', 'abfa3dc5-58ea-46da-9215-17e7072ff5fc', 'unify', 'The new leader tried to unify the party.', '新领导人试图统一全党。'),
  ('abfa3dc5-58ea-46da-9215-17e7072ff5fc-ex2', 'abfa3dc5-58ea-46da-9215-17e7072ff5fc', 'unify', 'The directive aims to unify divergent national standards.', '该指令旨在统一各不相同的国家标准。'),
  ('19b58583-9517-45c8-ab93-012c29490104-ex1', '19b58583-9517-45c8-ab93-012c29490104', 'unnecessary', 'That step is unnecessary.', '那一步没有必要。'),
  ('19b58583-9517-45c8-ab93-012c29490104-ex2', '19b58583-9517-45c8-ab93-012c29490104', 'unnecessary', 'The court found the restriction unnecessary and disproportionate.', '法院认定该限制既无必要也不相称。'),
  ('41104461-0071-4ac8-b3ce-724eeaff205c-ex1', '41104461-0071-4ac8-b3ce-724eeaff205c', 'unpleasant', 'The medicine has an unpleasant taste.', '这药味道不好。'),
  ('41104461-0071-4ac8-b3ce-724eeaff205c-ex2', '41104461-0071-4ac8-b3ce-724eeaff205c', 'unpleasant', 'The audit forced an unpleasant reckoning with years of complacency.', '审计迫使人们正视多年的自满，这一清算令人难堪。'),
  ('5590d23c-ac88-4830-8cdf-2dc61497033a-ex1', '5590d23c-ac88-4830-8cdf-2dc61497033a', 'unveil', 'They will unveil the new car tomorrow.', '他们明天发布新车。'),
  ('5590d23c-ac88-4830-8cdf-2dc61497033a-ex2', '5590d23c-ac88-4830-8cdf-2dc61497033a', 'unveil', 'The institute unveiled a framework for assessing platform liability.', '该研究所发布了一个评估平台责任的框架。'),
  ('d98ee9c9-f468-40ca-85f7-bf588ca3b0f0-ex1', 'd98ee9c9-f468-40ca-85f7-bf588ca3b0f0', 'upcoming', 'I am excited about the upcoming trip.', '我对即将到来的旅行很期待。'),
  ('d98ee9c9-f468-40ca-85f7-bf588ca3b0f0-ex2', 'd98ee9c9-f468-40ca-85f7-bf588ca3b0f0', 'upcoming', 'The upcoming review will test the framework''s resilience comprehensively.', '即将进行的审查将全面检验该框架的韧性。'),
  ('38f45238-ad4c-43b1-989c-64f3e2689bb8-ex1', '38f45238-ad4c-43b1-989c-64f3e2689bb8', 'upgrade', 'I want to upgrade my phone.', '我想升级我的手机。'),
  ('38f45238-ad4c-43b1-989c-64f3e2689bb8-ex2', '38f45238-ad4c-43b1-989c-64f3e2689bb8', 'upgrade', 'The agency upgraded the sovereign''s outlook following the fiscal reform.', '财政改革之后，该机构上调了这一主权信用展望。'),
  ('f85c1263-3e76-4b19-80c6-e0a29a0488fe-ex1', 'f85c1263-3e76-4b19-80c6-e0a29a0488fe', 'uphold', 'We must uphold the rules.', '我们必须维护规则。'),
  ('f85c1263-3e76-4b19-80c6-e0a29a0488fe-ex2', 'f85c1263-3e76-4b19-80c6-e0a29a0488fe', 'uphold', 'The appellate court upheld the award notwithstanding the procedural challenge.', '尽管存在程序质疑，上诉法院仍维持了该裁决。'),
  ('2abfc515-de9a-425d-8443-770600447d1c-ex1', '2abfc515-de9a-425d-8443-770600447d1c', 'upward', 'The path leads upward.', '这条路向上延伸。'),
  ('2abfc515-de9a-425d-8443-770600447d1c-ex2', '2abfc515-de9a-425d-8443-770600447d1c', 'upward', 'The upward revision of liabilities compelled an immediate capital raise.', '负债的向上修正迫使立即进行增资。'),
  ('d58e76da-11d1-46da-b94a-8fa1545b74ad-ex1', 'd58e76da-11d1-46da-b94a-8fa1545b74ad', 'urgent', 'This is an urgent matter.', '这是紧急事项。'),
  ('d58e76da-11d1-46da-b94a-8fa1545b74ad-ex2', 'd58e76da-11d1-46da-b94a-8fa1545b74ad', 'urgent', 'The assessment highlighted an urgent need for infrastructure investment.', '评估强调了对基础设施投资的迫切需要。'),
  ('bce9f1c6-5506-4d5c-a590-084af461daff-ex1', 'bce9f1c6-5506-4d5c-a590-084af461daff', 'usage', 'Check the word''s usage in a dictionary.', '在词典里查这个词的用法。'),
  ('bce9f1c6-5506-4d5c-a590-084af461daff-ex2', 'bce9f1c6-5506-4d5c-a590-084af461daff', 'usage', 'The court ascertained the term''s meaning from established trade usage.', '法院依据确立的行业惯例确定了该术语的含义。'),
  ('93b3752b-b5f2-4bd9-9fa0-428cb65784e4-ex1', '93b3752b-b5f2-4bd9-9fa0-428cb65784e4', 'useless', 'The broken umbrella is useless.', '坏掉的伞没用了。'),
  ('93b3752b-b5f2-4bd9-9fa0-428cb65784e4-ex2', '93b3752b-b5f2-4bd9-9fa0-428cb65784e4', 'useless', 'Safeguards that are never enforced are worse than useless.', '从不执行的保障措施比毫无用处还要糟糕。'),
  ('5d437e10-b23e-4ce4-94ae-43df276d7591-ex1', '5d437e10-b23e-4ce4-94ae-43df276d7591', 'utterly', 'I am utterly exhausted.', '我累得精疲力竭。'),
