  ('daf449d6-6f36-4b47-8db2-6d8e28d1d4c3-ex2', 'daf449d6-6f36-4b47-8db2-6d8e28d1d4c3', 'waiter', 'The waiter''s testimony placed the defendants at the scene that evening.', '这名服务员的证词将被告置于当晚的现场。'),
  ('17cc8989-fff0-4e27-8df9-4f2185c06424-ex1', '17cc8989-fff0-4e27-8df9-4f2185c06424', 'ward', 'The patient is in the children''s ward.', '病人在儿童病房。'),
  ('17cc8989-fff0-4e27-8df9-4f2185c06424-ex2', '17cc8989-fff0-4e27-8df9-4f2185c06424', 'ward', 'The redistricting diluted minority influence across several wards.', '选区重划稀释了几个选区内少数族裔的影响力。'),
  ('d9421055-cd00-40ff-a8b3-888976a23f69-ex1', 'd9421055-cd00-40ff-a8b3-888976a23f69', 'warfare', 'The museum covers ancient warfare.', '博物馆展示古代战争。'),
  ('d9421055-cd00-40ff-a8b3-888976a23f69-ex2', 'd9421055-cd00-40ff-a8b3-888976a23f69', 'warfare', 'Economic warfare through sanctions raises contested questions of legality.', '通过制裁开展的经济战引发了合法性方面的争议。'),
  ('84cb9a05-f36c-479b-9367-2458494a6788-ex1', '84cb9a05-f36c-479b-9367-2458494a6788', 'warming', 'Global warming affects the whole planet.', '全球变暖影响着整个地球。'),
  ('84cb9a05-f36c-479b-9367-2458494a6788-ex2', '84cb9a05-f36c-479b-9367-2458494a6788', 'warming', 'Attribution science increasingly links specific warming to specific emitters.', '归因科学日益将特定升温与特定排放者联系起来。'),
